import{_ as e,o as p,c as t,ai as r}from"./chunks/framework.CzqNhXfh.js";const h=JSON.parse('{"title":"22.10&11月记录与总结","description":"","frontmatter":{"layout":"doc"},"headers":[],"relativePath":"essays/articles/article-011.md","filePath":"essays/articles/article-011.md","lastUpdated":1776825361000}'),o={name:"essays/articles/article-011.md"};function s(l,a,i,c,n,_){return p(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="_22-10-11月记录与总结" tabindex="-1">22.10&amp;11月记录与总结 <a class="header-anchor" href="#_22-10-11月记录与总结" aria-label="Permalink to &quot;22.10&amp;11月记录与总结&quot;">​</a></h1><blockquote><p>子昱 闲谈之余 2022年12月7日 15:44 湖北</p></blockquote><p>呼~</p><p>两个月没笔写了，写作水平下降</p><p>这次总结与反省写这几个词：几个思考</p><h2 id="_1-总感觉" tabindex="-1">1.总感觉 <a class="header-anchor" href="#_1-总感觉" aria-label="Permalink to &quot;1.总感觉&quot;">​</a></h2><p>相比于开学一个月的状态，自然是好了不少。一颗心不再是摇摆不定不知个人还是旁人都对当过去了。在此时间，我也渐渐适应这新的环境。现实情况改善了许多。</p><p>从心随状态之上来看，我也稍稍悦了不少。随事无亢不卑，日常正常这个其实是很平和的。百闻争，我是不管它的。那些事情一定是又多又杂的。最重要的是，毕竟要把时间过。我知道了，我并不住边界简单化的人，一个凡人而已。各种情绪，绵延实实的豁达在我心中系绕不去。所以，你大胆承认好吧，过去家庭式的统统割去。</p><p>好好学习！天天向上！</p><h2 id="_2-思想境界" tabindex="-1">2.思想境界 <a class="header-anchor" href="#_2-思想境界" aria-label="Permalink to &quot;2.思想境界&quot;">​</a></h2><p>功利主义？利己主义？我时常质问自己。你可以做到很多事情无私奉献，乐于助人，我也对这点所感到丰礼骄慨。当我听放到一句警文已售，听着就好原词，我不在档彰为自己获得一丝利益，显然这对世界上去有些自私。不止否认，这的确是人性。可是你信能获得更好些呢，境界再高一些呢？</p><p>迷茫以周，所有很多只为谋求私人的人，也有无私为公为他人之义之人。事是人人都能但多为他人着想。以公为先，世苦自然关好。大同世界福临的大道之世，人人有位，人人欲思，人无外纪。人无外本纪阳完，人大不相过的遗志社会，谁不愿？尽三此大同世界是十遇但道对造后的世界（在某种程度上艾讲，是有进人性的。但我们大的追求并无益，咨于我们很多浴验的地方，很多人内心是有了名的形象和一点私欲的，随的明白思想高度为庶很为不了，我就为至此。</p><p>入身贫团气有失符一句，为共产主义立身终身，时时淮备为青们人牺牲一切。自头发展对象以来，我一直深来进去。压制在董情期义神国种吗？我见己卷教期如这结辨吗？足产党词，不应该成为一名道文口号。我在我手让自己的途程时暂获的义芳。当它看来，也是可以事名，我不打进算是一种逃这文回！义母起了高三语文老帅质坚主是英的，如果我导以能的无启一神被人抓住，我也不令屈服家一刻，至死不服！老师专我们及英我受的纪命，耳式百委，我终牛无总！</p><p>回到残次，我该如何行动？寡身名异，呈≈党员，何为党人，我相信行温之下，心1然干它！</p><h2 id="_3-嫉妒使人面目全非-多关注自己吧" tabindex="-1">3.嫉妒使人面目全非 多关注自己吧 <a class="header-anchor" href="#_3-嫉妒使人面目全非-多关注自己吧" aria-label="Permalink to &quot;3.嫉妒使人面目全非 多关注自己吧&quot;">​</a></h2><p>实话实说，右默是一一个有些嫉妒心的人。尤元是回别人得到了某柴西进你对他相左提，你很难不栅主出一些念头，往不正常的万向去道。你也是你内心的安协明。你地聪白此物非一时之要，蓄要长恨的靠胎等看思绍升。而望如果，你是不是也真犯了，在这方而日己然经长了不少了财，所以念归皮心好！</p><p>很大一部分原的，是你太关注告人了呀！</p><p>高中时期，为什么会有那么多人那么多何京，&quot;n让它在雨搭子？果然是f” 每次听则这些话，内心感想cr慕念， 他只暴多练一些练习，有何不可？有司也？当时流传这样一个关于f比关化话要说）后管大学南直疑，发现少了一介人，然是因川过像有人，久久不关门，大详忙推门，估计有人在课额切手机，是发现基在上床上的引久味题，人爷卫电叶家仪！</p><p>见法开玩笑，很多时候，实子不愿听到这样的问与，不愿计别人君司自己的努力，又敛若更优，很寡人局链有这种的懊统。</p><p>无论如何？因为我们招。</p><p>不三心的果乘人今欠亮，陷人讲，我们划人不讲，内心的独个前1会开始瓦翼。低年都气归的那些伤什么有用，且怎冰不到一烈律之人。义外的1。</p><p>离十去期的完时间不多，百膜改委名产折感，破承续展资，进刘与，走过局守。</p><p>你来到了人学，字在华中人，至今。</p><p>你发现了，你在一定程度上还是会去关注他人。你想和道位人在做什么，总怕自己事屏，现在佛逝来，是不显有内要？内纯有必要吗？没与</p><p>多青来自己，多行面前路。</p><p>无论如何，我依然相和容你！</p>',26)])])}const u=e(o,[["render",s]]);export{h as __pageData,u as default};
